class Solution {
    int ans = 0;
    int depth(TreeNode* n) {
        if (!n) return 0;
        int l = depth(n->left), r = depth(n->right);
        ans = max(ans, l + r);
        return 1 + max(l, r);
    }
public:
    int diameterOfBinaryTree(TreeNode* root) {
        depth(root);
        return ans;
    }
};
